SELECT [000_dam_AnalisiArriviMerceN_step0_TransferShipment].[Season Code], [000_dam_AnalisiArriviMerceN_step0_TransferReceipt].[Item No_], [000_dam_AnalisiArriviMerceN_step0_TransferShipment].[Constant Variable Code], [000_dam_AnalisiArriviMerceN_step0_TransferShipment].[Transfer Order No_], [000_dam_AnalisiArriviMerceN_step0_TransferShipment].Note, [000_dam_AnalisiArriviMerceN_step0_TransferShipment].[Document No_] AS Trs_DocNr, [000_dam_AnalisiArriviMerceN_step0_TransferShipment].[Shipment Date], [000_dam_AnalisiArriviMerceN_step0_TransferReceipt].[Document No_] AS Trc_DocNr, [000_dam_AnalisiArriviMerceN_step0_TransferReceipt].[Receipt Date], [000_dam_AnalisiArriviMerceN_step0_TransferShipment].QTY AS QTY_ship, [000_dam_AnalisiArriviMerceN_step0_TransferReceipt].QTY AS QTY_rec, DateDiff("d",[Shipment Date],[Receipt Date]) AS TransitTime, [qty_SHIP]*[TransitTime] AS QTYxTransitTime
FROM 000_dam_AnalisiArriviMerceN_step0_TransferShipment INNER JOIN 000_dam_AnalisiArriviMerceN_step0_TransferReceipt ON ([000_dam_AnalisiArriviMerceN_step0_TransferReceipt].[Item No_] = [000_dam_AnalisiArriviMerceN_step0_TransferShipment].[Item No_]) AND ([000_dam_AnalisiArriviMerceN_step0_TransferShipment].[Transfer Order No_] = [000_dam_AnalisiArriviMerceN_step0_TransferReceipt].[Transfer Order No_]) AND ([000_dam_AnalisiArriviMerceN_step0_TransferShipment].[Constant Variable Code] = [000_dam_AnalisiArriviMerceN_step0_TransferReceipt].[Constant Variable Code]);

